1	package agent
2	
3	import (
4		"context"
5		"net/http"
6		"strconv"
7		"strings"
8		"time"
9	
10		agentlib "github.com/easel/fizeau"
11	)
12	
13	// RateLimitRetryDefaultBudget is the default per-bead total wait budget for
14	// rate-limit retries. AC #4 of ddx-c6e3db02 names 5 minutes.
15	const RateLimitRetryDefaultBudget = 5 * time.Minute
16	
17	// RateLimitRetryDefaultPerWaitCap caps any single retry wait so a misbehaving
18	// provider cannot pin the worker with a one-hour Retry-After. The bead
19	// description names 60 seconds as the per-wait cap.
20	const RateLimitRetryDefaultPerWaitCap = 60 * time.Second
21	
22	// RateLimitBudgetExhaustedReason is the canonical reason string written into
23	// Result.Error when the per-bead retry budget is exhausted. The execute-bead
24	// status mapping translates this into FailureModeAuthError so it surfaces in
25	// the standard execution_failed pathway (TD-031 §8.4).
26	const RateLimitBudgetExhaustedReason = "rate-limited beyond budget"
27	
28	// RateLimitRetryEventKind is the bead event kind appended on each retry per
29	// TD-031 §4 / §8.4 RateLimitRetryContract. The body carries the retry count
30	// and wait duration.
31	const RateLimitRetryEventKind = "rate-limit-retry"
32	
33	// rateLimitBackoffSchedule is the exponential-backoff fallback when a 429
34	// response carries no parseable Retry-After value. The schedule names the
35	// wait for the 1st, 2nd, … retry; entries past the end repeat the last value.
36	// AC #3 of ddx-c6e3db02 specifies 1s, 5s, 15s, 30s, 60s.
37	var rateLimitBackoffSchedule = []time.Duration{
38		1 * time.Second,
39		5 * time.Second,
40		15 * time.Second,
41		30 * time.Second,
42		60 * time.Second,
43	}
44	
45	// RateLimitWaitDecision is the policy output for one rate-limit response.
46	// The policy never mutates state; the caller decides whether to wait + retry
47	// or to give up and surface RateLimitBudgetExhaustedReason.
48	type RateLimitWaitDecision struct {
49		// ShouldRetry is true when the budget allows another wait + retry.
50		ShouldRetry bool
51		// Wait is the duration the caller should sleep before retrying.
52		// Only meaningful when ShouldRetry is true.
53		Wait time.Duration
54		// Source classifies how Wait was derived: "retry-after" when the upstream
55		// response named a specific delay, "exponential-backoff" when the schedule
56		// fallback was used. Empty when ShouldRetry is false.
57		Source string
58		// Reason is populated when ShouldRetry is false; carries
59		// RateLimitBudgetExhaustedReason in the budget-exhausted case.
60		Reason string
61	}
62	
63	// EvaluateRateLimitWait decides how long to wait before retrying after a
64	// rate-limit response, and whether the per-bead budget allows the retry.
65	//
66	// retryAfter is the duration parsed from the response (zero when absent /
67	// unparseable). attempt is 1-indexed (first retry = 1). elapsed is the total
68	// wait already spent on this bead. budget is the total cap (zero = unbounded,
69	// disabling budget enforcement). perWaitCap caps any single wait (zero =
70	// uncapped).
71	//
72	// The function is pure: no I/O, no time.Now, no global state.
73	func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
74		if budget > 0 && elapsed >= budget {
75			return RateLimitWaitDecision{
76				ShouldRetry: false,
77				Reason:      RateLimitBudgetExhaustedReason,
78			}
79		}
80	
81		var wait time.Duration
82		var source string
83		if retryAfter > 0 {
84			wait = retryAfter
85			source = "retry-after"
86		} else {
87			idx := attempt - 1
88			if idx < 0 {
89				idx = 0
90			}
91			if idx >= len(rateLimitBackoffSchedule) {
92				idx = len(rateLimitBackoffSchedule) - 1
93			}
94			wait = rateLimitBackoffSchedule[idx]
95			source = "exponential-backoff"
96		}
97	
98		if perWaitCap > 0 && wait > perWaitCap {
99			wait = perWaitCap
100		}
101	
102		if budget > 0 && elapsed+wait > budget {
103			// Trim the final wait so the bead doesn't block beyond the budget.
104			// If trimming leaves nothing, treat the budget as exhausted.
105			remaining := budget - elapsed
106			if remaining <= 0 {
107				return RateLimitWaitDecision{
108					ShouldRetry: false,
109					Reason:      RateLimitBudgetExhaustedReason,
110				}
111			}
112			wait = remaining
113		}
114	
115		return RateLimitWaitDecision{
116			ShouldRetry: true,
117			Wait:        wait,
118			Source:      source,
119		}
120	}
121	
122	// IsRateLimitResult reports whether a Runner Result indicates a rate-limit
123	// (HTTP 429) event that the per-bead retry policy should handle.
124	//
125	// Quota exhaustion (NoViableProviderForNow) is OUT of scope for
126	// RateLimitRetryContract per ddx-c6e3db02 AC #8 — it belongs to
127	// QuotaPauseContract (ddx-aede917d). The detection here matches the canonical
128	// 429 / "rate limit" / "ratelimit" markers without matching "quota exceeded".
129	func IsRateLimitResult(result *Result) bool {
130		if result == nil {
131			return false
132		}
133		combined := strings.ToLower(result.Error + "\n" + result.Stderr)
134		if combined == "\n" {
135			return false
136		}
137		// Quota wording must NOT match: that path is QuotaPauseContract
138		// (ddx-aede917d), not RateLimitRetryContract.
139		if strings.Contains(combined, "quota exceeded") ||
140			strings.Contains(combined, "insufficient quota") ||
141			strings.Contains(combined, "no viable provider") {
142			return false
143		}
144		if strings.Contains(combined, "rate limit") ||
145			strings.Contains(combined, "ratelimit") {
146			return true
147		}
148		// Match HTTP 429 with word boundary around the digits — avoid matching
149		// "port 4290" or fragment timestamps. The conservative form is to look
150		// for "429" framed by non-digits or as an HTTP status marker.
151		if hasIsolated429(combined) {
152			return true
153		}
154		return false
155	}
156	
157	// hasIsolated429 returns true when the input contains "429" framed so it
158	// cannot be a substring of a longer number (e.g. "4290", "12429"). A simple
159	// scan is enough — the haystack is short.
160	func hasIsolated429(s string) bool {
161		for i := 0; i+3 <= len(s); i++ {
162			if s[i:i+3] != "429" {
163				continue
164			}
165			// Check left boundary.
166			if i > 0 {
167				c := s[i-1]
168				if c >= '0' && c <= '9' {
169					continue
170				}
171			}
172			// Check right boundary.
173			if i+3 < len(s) {
174				c := s[i+3]
175				if c >= '0' && c <= '9' {
176					continue
177				}
178			}
179			return true
180		}
181		return false
182	}
183	
184	// ParseRetryAfter parses a Retry-After header value per RFC 7231 §7.1.3:
185	// either a non-negative integer ("delta-seconds") or an HTTP-date.
186	// Returns zero duration when the value is empty or unparseable.
187	//
188	// now is supplied so tests can pin the clock; production callers pass
189	// time.Now().
190	func ParseRetryAfter(value string, now time.Time) time.Duration {
191		value = strings.TrimSpace(value)
192		if value == "" {
193			return 0
194		}
195		if secs, err := strconv.Atoi(value); err == nil {
196			if secs < 0 {
197				return 0
198			}
199			return time.Duration(secs) * time.Second
200		}
201		// HTTP-date: RFC 1123 / 850 / asctime per http.ParseTime.
202		if t, err := http.ParseTime(value); err == nil {
203			d := t.Sub(now)
204			if d < 0 {
205				return 0
206			}
207			return d
208		}
209		// Last resort: a Go duration literal ("30s", "2m"). Some harnesses emit
210		// this style on stderr; treat it as a courtesy.
211		if d, err := time.ParseDuration(value); err == nil && d >= 0 {
212			return d
213		}
214		return 0
215	}
216	
217	// ExtractRetryAfterFromStderr scans subprocess stderr for a Retry-After
218	// indication and returns the parsed wait. Returns zero when no indication is
219	// present so the caller falls back to exponential backoff.
220	//
221	// Recognised forms (case-insensitive):
222	//   - "Retry-After: <value>" (HTTP header echoed by the harness)
223	//   - "retry_after=<value>" (structured key=value form some harnesses emit)
224	//   - "retry after <value>"
225	//
226	// now is used as the reference for HTTP-date values.
227	func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
228		if stderr == "" {
229			return 0
230		}
231		lower := strings.ToLower(stderr)
232		for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
233			idx := strings.Index(lower, marker)
234			if idx < 0 {
235				continue
236			}
237			rest := stderr[idx+len(marker):]
238			// Read up to the end of the line.
239			if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
240				rest = rest[:eol]
241			}
242			// Strip surrounding quotes/spaces and an optional comma terminator.
243			rest = strings.TrimSpace(rest)
244			rest = strings.Trim(rest, "\"',")
245			if d := ParseRetryAfter(rest, now); d > 0 {
246				return d
247			}
248		}
249		return 0
250	}
251	
252	// RateLimitRetryConfig configures the retry wrapper. Zero values mean
253	// "use the package default".
254	type RateLimitRetryConfig struct {
255		// Budget caps the total wait this bead may spend on rate-limit retries.
256		// Zero uses RateLimitRetryDefaultBudget. Negative disables retries entirely.
257		Budget time.Duration
258		// PerWaitCap caps a single retry wait. Zero uses
259		// RateLimitRetryDefaultPerWaitCap.
260		PerWaitCap time.Duration
261		// Sleep is the function the wrapper calls between attempts. Defaults to
262		// a context-aware time.Sleep. Tests inject a fake to avoid real waits.
263		Sleep func(ctx context.Context, d time.Duration) error
264		// Now returns the current time for HTTP-date arithmetic. Defaults to
265		// time.Now.
266		Now func() time.Time
267		// OnRetry, when non-nil, is invoked after each wait + before the retry
268		// attempt fires. Used by integration to emit the rate-limit-retry bead
269		// event and the routing-engine RecordRouteAttempt feedback.
270		OnRetry func(ctx context.Context, info RateLimitRetryInfo)
271	}
272	
273	// RateLimitRetryInfo describes one rate-limit retry event for telemetry hooks.
274	type RateLimitRetryInfo struct {
275		Attempt    int
276		Wait       time.Duration
277		Source     string
278		Result     *Result
279		Elapsed    time.Duration
280		OverBudget bool
281	}
282	
283	// resolved returns a copy of cfg with zero fields filled in from defaults.
284	func (cfg RateLimitRetryConfig) resolved() RateLimitRetryConfig {
285		out := cfg
286		if out.Budget == 0 {
287			out.Budget = RateLimitRetryDefaultBudget
288		}
289		if out.PerWaitCap == 0 {
290			out.PerWaitCap = RateLimitRetryDefaultPerWaitCap
291		}
292		if out.Sleep == nil {
293			out.Sleep = ctxSleep
294		}
295		if out.Now == nil {
296			out.Now = time.Now
297		}
298		return out
299	}
300	
301	func ctxSleep(ctx context.Context, d time.Duration) error {
302		if d <= 0 {
303			return nil
304		}
305		t := time.NewTimer(d)
306		defer t.Stop()
307		select {
308		case <-ctx.Done():
309			return ctx.Err()
310		case <-t.C:
311			return nil
312		}
313	}
314	
315	// RunWithRateLimitRetry invokes attempt and, when its result is a rate-limit
316	// signal per IsRateLimitResult, waits per EvaluateRateLimitWait and retries
317	// until either attempt returns a non-rate-limit result or the per-bead budget
318	// is exhausted. Budget exhaustion mutates the final result's Error to
319	// RateLimitBudgetExhaustedReason and returns it without further retries.
320	//
321	// The wrapper does NOT change provider availability state — the provider
322	// stays in rotation per AC #2 of ddx-c6e3db02. Per AC #6, callers wire
323	// RecordRouteAttempt via OnRetry for transparency.
324	func RunWithRateLimitRetry(ctx context.Context, cfg RateLimitRetryConfig, attempt func(ctx context.Context) (*Result, error)) (*Result, error) {
325		if cfg.Budget < 0 {
326			// Negative budget disables the wrapper entirely (parity with
327			// "feature off"). Useful for tests and operator opt-out.
328			return attempt(ctx)
329		}
330		cfg = cfg.resolved()
331	
332		var (
333			elapsed    time.Duration
334			retryCount int
335		)
336		for {
337			res, err := attempt(ctx)
338			if err != nil || res == nil {
339				return res, err
340			}
341			if !IsRateLimitResult(res) {
342				return res, nil
343			}
344	
345			retryCount++
346			retryAfter := ExtractRetryAfterFromStderr(res.Stderr, cfg.Now())
347			decision := EvaluateRateLimitWait(retryAfter, retryCount, elapsed, cfg.Budget, cfg.PerWaitCap)
348			if !decision.ShouldRetry {
349				// Budget exhausted: surface the canonical reason so the standard
350				// execution_failed mapping fires (TD-031 §5).
351				res.Error = RateLimitBudgetExhaustedReason
352				if cfg.OnRetry != nil {
353					cfg.OnRetry(ctx, RateLimitRetryInfo{
354						Attempt:    retryCount,
355						Source:     decision.Source,
356						Result:     res,
357						Elapsed:    elapsed,
358						OverBudget: true,
359					})
360				}
361				return res, nil
362			}
363	
364			if cfg.OnRetry != nil {
365				cfg.OnRetry(ctx, RateLimitRetryInfo{
366					Attempt: retryCount,
367					Wait:    decision.Wait,
368					Source:  decision.Source,
369					Result:  res,
370					Elapsed: elapsed,
371				})
372			}
373	
374			if err := cfg.Sleep(ctx, decision.Wait); err != nil {
375				return res, err
376			}
377			elapsed += decision.Wait
378		}
379	}
380	
381	// BuildRateLimitRouteAttempt constructs a fizeau.RouteAttempt that records a
382	// rate-limit retry on the routing-engine feedback channel. The Status is
383	// "rate_limited" so the engine has signal even though provider availability
384	// remains unchanged per RateLimitRetryContract.
385	func BuildRateLimitRouteAttempt(info RateLimitRetryInfo) agentlib.RouteAttempt {
386		att := agentlib.RouteAttempt{
387			Status:    "rate_limited",
388			Reason:    info.Source,
389			Duration:  info.Wait,
390			Timestamp: time.Now().UTC(),
391		}
392		if info.Result != nil {
393			att.Harness = info.Result.Harness
394			att.Provider = info.Result.Provider
395			att.Model = info.Result.Model
396			att.Error = info.Result.Error
397		}
398		if info.OverBudget {
399			att.Reason = RateLimitBudgetExhaustedReason
400		}
401		return att
402	}
