77	// Final wait is trimmed so it doesn't push elapsed past the budget.
78	func TestEvaluateRateLimitWait_TrimsFinalWaitToBudget(t *testing.T) {
79		d := EvaluateRateLimitWait(60*time.Second, 5, 4*time.Minute+30*time.Second, 5*time.Minute, 60*time.Second)
80		if !d.ShouldRetry {
81			t.Fatalf("ShouldRetry: got false; want true")
82		}
83		if d.Wait != 30*time.Second {
84			t.Fatalf("Wait: got %v; want trimmed 30s", d.Wait)
85		}
86	}
