133	func TestIsRateLimitResult(t *testing.T) {
134		cases := []struct {
135			name string
136			res  *Result
137			want bool
138		}{
139			{"nil", nil, false},
140			{"empty", &Result{}, false},
141			{
142				name: "early-cancel 429 in stderr",
143				res:  &Result{Error: "cancelled: auth/rate-limit detected (\\b429\\b)", Stderr: "HTTP/1.1 429 Too Many Requests"},
144				want: true,
145			},
146			{
147				name: "rate limit phrase in stderr",
148				res:  &Result{Stderr: "Rate limit exceeded; back off"},
149				want: true,
150			},
151			{
152				name: "ratelimit phrase in error",
153				res:  &Result{Error: "ratelimit hit"},
154				want: true,
155			},
156			{
157				name: "quota wording must NOT match (QuotaPauseContract owns it)",
158				res:  &Result{Error: "quota exceeded"},
159				want: false,
160			},
161			{
162				name: "no viable provider must NOT match",
163				res:  &Result{Error: "no viable provider for now"},
164				want: false,
165			},
166			{
167				name: "isolated 429 yes",
168				res:  &Result{Error: "remote returned 429"},
169				want: true,
170			},
171			{
172				name: "embedded 4290 must not match",
173				res:  &Result{Error: "received port 4290 from upstream"},
174				want: false,
175			},
176		}
177		for _, c := range cases {
178			t.Run(c.name, func(t *testing.T) {
179				got := IsRateLimitResult(c.res)
180				if got != c.want {
181					t.Errorf("IsRateLimitResult: got %v; want %v", got, c.want)
182				}
183			})
184		}
185	}
