187	// TestRunWithRateLimitRetry_RetryAfterRespected covers AC #1, #3, #6, #7:
188	// a rate-limited result is retried with the exact Retry-After-derived wait,
189	// the OnRetry hook fires (this is the channel callers use to invoke
190	// RecordRouteAttempt), and a subsequent non-rate-limit result terminates the
191	// loop.
192	func TestRunWithRateLimitRetry_RetryAfterRespected(t *testing.T) {
193		var sleepCalls []time.Duration
194		var hookCalls []RateLimitRetryInfo
195	
196		cfg := RateLimitRetryConfig{
197			Budget:     5 * time.Minute,
198			PerWaitCap: 60 * time.Second,
199			Sleep: func(_ context.Context, d time.Duration) error {
200				sleepCalls = append(sleepCalls, d)
201				return nil
202			},
203			Now: func() time.Time { return time.Date(2026, 5, 3, 12, 0, 0, 0, time.UTC) },
204			OnRetry: func(_ context.Context, info RateLimitRetryInfo) {
