257		}
258	
259		calls := 0
260		attempt := func(ctx context.Context) (*Result, error) {
261			calls++
262			if calls < 3 {
263				// Two consecutive rate-limit responses, no Retry-After.
264				return &Result{Stderr: "Rate limit exceeded; please slow down"}, nil
265			}
266			return &Result{Output: "done"}, nil
267		}
268	
269		res, err := RunWithRateLimitRetry(context.Background(), cfg, attempt)
270		if err != nil {
271			t.Fatalf("err = %v", err)
272		}
273		if res.Output != "done" {
274			t.Fatalf("final result not propagated; got %+v", res)
275		}
276		if calls != 3 {
277			t.Fatalf("attempt invoked %d times; want 3", calls)
278		}
279		want := []time.Duration{1 * time.Second, 5 * time.Second}
280		if len(sleepCalls) != len(want) {
281			t.Fatalf("sleeps = %v; want %v", sleepCalls, want)
282		}
283		for i := range want {
284			if sleepCalls[i] != want[i] {
