290	// TestRunWithRateLimitRetry_BudgetExhausted covers AC #5: past budget, the
291	// final result carries the canonical RateLimitBudgetExhaustedReason in
292	// Error so the standard execution_failed status mapping fires (TD-031 §5).
293	// Per AC #2, no provider state is mutated by the wrapper itself.
294	func TestRunWithRateLimitRetry_BudgetExhausted(t *testing.T) {
295		var hookCalls []RateLimitRetryInfo
296		cfg := RateLimitRetryConfig{
297			// Tiny budget so two rate-limited responses exhaust it.
298			Budget:     2 * time.Second,
299			PerWaitCap: 1 * time.Second,
300			Sleep:      func(_ context.Context, _ time.Duration) error { return nil },
301			Now:        func() time.Time { return time.Now() },
302			OnRetry: func(_ context.Context, info RateLimitRetryInfo) {
303				hookCalls = append(hookCalls, info)
304			},
305		}
306	
307		attempt := func(ctx context.Context) (*Result, error) {
308			// Always rate-limited; no Retry-After.
309			return &Result{Stderr: "rate limit exceeded"}, nil
310		}
311	
312		res, err := RunWithRateLimitRetry(context.Background(), cfg, attempt)
313		if err != nil {
314			t.Fatalf("err = %v", err)
315		}
316		if !strings.Contains(res.Error, RateLimitBudgetExhaustedReason) {
317			t.Fatalf("final Error = %q; want to contain %q", res.Error, RateLimitBudgetExhaustedReason)
318		}
319		if len(hookCalls) == 0 {
320			t.Fatal("OnRetry never invoked")
321		}
322		// Last hook call must mark OverBudget so RecordRouteAttempt can record
323		// the budget-exhausted terminal event.
324		last := hookCalls[len(hookCalls)-1]
325		if !last.OverBudget {
326			t.Fatalf("last hook OverBudget = false; want true")
327		}
328	}
