197	func Attempt(ctx context.Context, store Store, beadID string, opts AttemptOpts) (Outcome, error) {
198		if opts.Executor == nil {
199			return Outcome{}, fmt.Errorf("try attempt: executor is required")
200		}
201		rateCfg := resolveRateLimitRetryConfig(opts)
202		var (
203			report Report
204			err    error
205		)
206		for retryCount, elapsed := 0, time.Duration(0); ; {
207			report, err = opts.Executor.Execute(ctx, beadID)
208			if err != nil {
209				report = Report{
210					BeadID: beadID,
211					Status: StatusExecutionFailed,
212					Detail: err.Error(),
213					Error:  err.Error(),
214				}
215			}
216			if report.BeadID == "" {
217				report.BeadID = beadID
218			}
219			if report.Status == "" {
220				report.Status = StatusExecutionFailed
221			}
222			if ctx != nil && ctx.Err() != nil {
223				if err == nil {
224					err = ctx.Err()
225				}
226				if report.Error == "" {
227					report.Error = ctx.Err().Error()
228				}
229				if report.Detail == "" {
230					report.Detail = ctx.Err().Error()
231				}
232				return Outcome{Report: report, Disposition: OutcomeReported}, err
233			}
234	
235			rateLimited := IsRateLimitReport(&report)
236			effectiveBudget := rateCfg.Budget
237			if opts.RateLimitBudget == 0 && report.RateLimitBudget != 0 {
238				effectiveBudget = report.RateLimitBudget
239			}
240			decision, retryAfter := evaluateRateLimitAttempt(report, rateCfg, retryCount+1, elapsed, effectiveBudget)
241			if !decision.ShouldRetry {
242				if decision.Reason != "" {
243					report.Error = decision.Reason
244				}
245				if rateLimited && decision.Reason != "" && rateCfg.OnRetry != nil {
246					rateCfg.OnRetry(ctx, RateLimitRetryInfo{
247						Attempt:    retryCount + 1,
248						Source:     decision.Source,
249						Report:     &report,
250						Elapsed:    elapsed,
251						RetryAfter: retryAfter,
252						OverBudget: true,
253					})
254				}
255				break
256			}
257	
258			retryCount++
259			info := RateLimitRetryInfo{
260				Attempt:    retryCount,
261				Wait:       decision.Wait,
262				Source:     decision.Source,
263				Report:     &report,
264				Elapsed:    elapsed,
265				RetryAfter: retryAfter,
266			}
267			if rateCfg.OnRetry != nil {
268				rateCfg.OnRetry(ctx, info)
269			}
270			if err := rateCfg.Sleep(ctx, decision.Wait); err != nil {
271				return Outcome{}, err
272			}
273			elapsed += decision.Wait
274		}
275	
276		if ShouldAttemptConflictRecovery(report, opts.ProjectRoot) {
277			if opts.Store == nil {
278				opts.Store = store
279			}
280			return ConflictRecoveryOutcome(ctx, ConflictRecoveryInput{
281				Bead:             opts.Bead,
282				Report:           report,
283				ProjectRoot:      opts.ProjectRoot,
284				AutoRecover:      opts.AutoRecover,
285				ConflictResolver: opts.ConflictResolver,
286				Store:            opts.Store,
287				Assignee:         opts.Assignee,
288				Now:              opts.Now,
289				Cooldown:         opts.Cooldown,
290			}), err
291		}
292	
293		if report.Status == StatusNoChanges {
294			if opts.Store == nil {
295				opts.Store = store
296			}
297			if opts.Store == nil {
298				return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: fmt.Errorf("try attempt: no_changes store is required")}, nil
299			}
300			noChangesCount, countErr := opts.Store.IncrNoChangesCount(beadID)
301			if countErr != nil {
302				return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: countErr}, nil
303			}
304			noChangesOut, adjudicatedReport, adjErr := adjudicateNoChangesContract(ctx, beadID, report, opts.ProjectRoot, noChangesCount, opts.SatisfactionChecker, opts.VerificationRunner)
305			if adjErr != nil {
306				return Outcome{Report: report, StoreErrOp: "adjudicateNoChanges", StoreErr: adjErr}, nil
307			}
308			return Outcome{
309				Report:      adjudicatedReport,
310				Disposition: OutcomeReported,
311				NoChanges:   &noChangesOut,
312			}, nil
313		}
314	
315		if report.Status == StatusDeclinedNeedsDecomposition {
316			effectiveStore := opts.Store
317			if effectiveStore == nil {
318				effectiveStore = store
319			}
320			if effectiveStore != nil {
321				if err := effectiveStore.UpdateWithLifecycleStatus(beadID, bead.StatusOpen, bead.LifecycleTransitionOptions{
322					Reason: "declined: bead requires decomposition before execution",
323					Source: "legacy agent try",
324				}, func(b *bead.Bead) error {
325					if b.Extra == nil {
326						b.Extra = make(map[string]any)
327					}
328					b.Extra[bead.ExtraExecutionElig] = false
329					return nil
330				}); err != nil {
331					return Outcome{Report: report, StoreErrOp: "UpdateWithLifecycleStatus", StoreErr: err}, nil
332				}
333			}
334			event := buildDecompositionParkingEvent(report)
335			return Outcome{
336				Report:      report,
337				Disposition: OutcomePark,
338				Parking: &ParkingOutcome{
339					Unclaim:              true,
340					RunPostAttemptTriage: true,
341					Event:                event,
342				},
343			}, nil
344		}
345	
346		if report.Status == StatusPushConflict {
347			parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
348			report.RetryAfter = parkUntil.Format(time.RFC3339)
349			event := buildPushConflictParkingEvent(report)
350			return Outcome{
351				Report:      report,
352				Disposition: OutcomePark,
353				Parking: &ParkingOutcome{
354					Unclaim:              true,
355					RetryAfter:           parkUntil,
356					RunPostAttemptTriage: true,
357					Event:                event,
358				},
359			}, nil
360		}
361	
362		return Outcome{Report: report, Disposition: OutcomeReported}, err
363	}
