374	func buildDecompositionParkingEvent(report Report) *ParkingEvent {
375		body, mErr := json.Marshal(map[string]any{
376			"rationale":            report.DecompositionRationale,
377			"recommended_subbeads": report.DecompositionRecommendation,
378			"detail":               report.Detail,
379			"base_rev":             report.BaseRev,
380			"session_id":           report.SessionID,
381		})
382		bodyStr := ""
383		if mErr == nil {
384			bodyStr = string(body)
385		} else {
386			bodyStr = fmt.Sprintf("rationale=%s\nrecommended_subbeads=%v",
387				report.DecompositionRationale, report.DecompositionRecommendation)
388		}
389		summary := "agent declined: needs decomposition"
390		if n := len(report.DecompositionRecommendation); n > 0 {
391			summary = fmt.Sprintf("%s (%d sub-beads)", summary, n)
392		}
393		return &ParkingEvent{
394			Kind:    "decomposition-recommendation",
395			Summary: summary,
396			Body:    bodyStr,
397		}
398	}
