400	func buildPushConflictParkingEvent(report Report) *ParkingEvent {
401		body, mErr := json.Marshal(map[string]any{
402			"detail":     report.Detail,
403			"base_rev":   report.BaseRev,
404			"result_rev": report.ResultRev,
405			"session_id": report.SessionID,
406		})
407		bodyStr := report.Detail
408		if mErr == nil {
409			bodyStr = string(body)
410		}
411		return &ParkingEvent{
412			Kind:    "push-conflict",
413			Summary: "auto-merge after push race could not be resolved",
414			Body:    bodyStr,
415		}
416	}
