571	func hasIsolated429(s string) bool {
572		for i := 0; i+3 <= len(s); i++ {
573			if s[i:i+3] != "429" {
574				continue
575			}
576			if i > 0 {
577				c := s[i-1]
578				if c >= '0' && c <= '9' {
579					continue
580				}
581			}
582			if i+3 < len(s) {
583				c := s[i+3]
584				if c >= '0' && c <= '9' {
585					continue
586				}
587			}
