594		value = strings.TrimSpace(value)
595		if value == "" {
596			return 0
597		}
598		if secs, err := strconv.Atoi(value); err == nil {
599			if secs < 0 {
600				return 0
601			}
602			return time.Duration(secs) * time.Second
603		}
604		if t, err := http.ParseTime(value); err == nil {
605			d := t.Sub(now)
606			if d < 0 {
607				return 0
608			}
609			return d
610		}
611		if d, err := time.ParseDuration(value); err == nil && d >= 0 {
612			return d
613		}
614		return 0
615	}
