617	func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
618		if stderr == "" {
619			return 0
620		}
621		lower := strings.ToLower(stderr)
622		for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
623			idx := strings.Index(lower, marker)
624			if idx < 0 {
625				continue
626			}
627			rest := stderr[idx+len(marker):]
628			if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
629				rest = rest[:eol]
630			}
631			rest = strings.TrimSpace(rest)
632			rest = strings.Trim(rest, "\"',")
633			if d := ParseRetryAfter(rest, now); d > 0 {
634				return d
635			}
636		}
637		return 0
638	}
